// Instance browser — list entities, filter by JTBD/state/tenant.
// Generated by flowforge JTBD generator — do not edit by hand.
import * as React from "react";

import { adminApi, type AdminInstance, type InstanceFilters } from "../api";

interface JtbdMeta {
	id: string;
	title: string;
	url_segment: string;
}

const JTBDS: ReadonlyArray<JtbdMeta> = [
	{ id: "field_inspection", title: "Conduct Field Inspection", url_segment: "field-inspection" },
	{ id: "permit_decision", title: "Approve or Deny Building Permit", url_segment: "permit-decision" },
	{ id: "permit_intake", title: "Submit a Building Permit Application", url_segment: "permit-intake" },
	{ id: "permit_issuance", title: "Issue the Building Permit Certificate", url_segment: "permit-issuance" },
	{ id: "plan_review", title: "Review Building Plans for Code Compliance", url_segment: "plan-review" },
];

export function InstanceBrowser(): React.ReactElement {
	const [filters, setFilters] = React.useState<InstanceFilters>({});
	const [rows, setRows] = React.useState<ReadonlyArray<AdminInstance>>([]);
	const [error, setError] = React.useState<string | null>(null);
	const [busy, setBusy] = React.useState(false);

	const load = React.useCallback(async () => {
		setBusy(true);
		setError(null);
		try {
			const data = await adminApi.listInstances(filters);
			setRows(data);
		} catch (e: unknown) {
			setError(e instanceof Error ? e.message : "load failed");
		} finally {
			setBusy(false);
		}
	}, [filters]);

	React.useEffect(() => {
		void load();
	}, [load]);

	return (
		<section aria-labelledby="instances-heading">
			<h2 id="instances-heading">Instances</h2>
			<form
				className="ff-admin-filters"
				onSubmit={(e) => {
					e.preventDefault();
					void load();
				}}
			>
				<label>
					JTBD
					<select
						value={filters.jtbd ?? ""}
						onChange={(e) => setFilters({ ...filters, jtbd: e.target.value || undefined })}
					>
						<option value="">all</option>
						{JTBDS.map((j) => (
							<option key={j.id} value={j.id}>
								{j.title}
							</option>
						))}
					</select>
				</label>
				<label>
					State
					<input
						type="text"
						value={filters.state ?? ""}
						onChange={(e) => setFilters({ ...filters, state: e.target.value || undefined })}
						placeholder="(any)"
					/>
				</label>
				<label>
					Tenant
					<input
						type="text"
						value={filters.tenant ?? ""}
						onChange={(e) => setFilters({ ...filters, tenant: e.target.value || undefined })}
						placeholder="(any)"
					/>
				</label>
				<button type="submit" disabled={busy}>
					{busy ? "Loading…" : "Apply"}
				</button>
			</form>
			{error ? (
				<p role="alert" className="ff-admin-error">
					{error}
				</p>
			) : null}
			<table className="ff-admin-table">
				<thead>
					<tr>
						<th scope="col">Instance</th>
						<th scope="col">JTBD</th>
						<th scope="col">State</th>
						<th scope="col">Tenant</th>
						<th scope="col">Updated</th>
					</tr>
				</thead>
				<tbody>
					{rows.map((row) => (
						<tr key={row.id}>
							<td>
								<code>{row.id}</code>
							</td>
							<td>{row.jtbd_id}</td>
							<td>
								<code>{row.state}</code>
							</td>
							<td>{row.tenant_id}</td>
							<td>
								<time dateTime={row.updated_at}>{row.updated_at}</time>
							</td>
						</tr>
					))}
					{rows.length === 0 && !busy ? (
						<tr>
							<td colSpan={5}>no instances match these filters</td>
						</tr>
					) : null}
				</tbody>
			</table>
		</section>
	);
}
